import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define the custom CUDA kernel for GELU computation
gelu_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <c10/cuda/CUDAGuard.h>
#include <math.h>
#include <cassert>

namespace {
constexpr float GELU_COEF = 0.044715f;
constexpr float SQRT_2_OVER_PI = 0.7978845608028654f;  // sqrt(2/π)
}

template<typename T>
__device__ T fast_tanh(T x) {
    // More accurate tanh approximation for GELU
    if (x < -4.97f) return T(-1.0f);
    if (x > 4.97f) return T(1.0f);
    T x2 = x * x;
    T a = x * (T(135135.0f) + x2 * (T(17325.0f) + x2 * (T(378.0f) + x2)));
    T b = T(135135.0f) + x2 * (T(62370.0f) + x2 * (T(3150.0f) + x2 * T(28.0f)));
    return a / b;
}

template<typename T>
__device__ inline int safe_calc_index(int block_idx, int block_dim, int thread_idx) {
    // Consistent, robust index calculation with assertion in debug mode
    int idx = block_idx * block_dim + thread_idx;
    // Add debug assertion (compiles out in release with NDEBUG)
    assert(idx >= 0 && "Negative index calculated!");
    return idx;
}

template<typename T>
__global__ void gelu_kernel(const T* __restrict__ input, T* __restrict__ output, int size) {
    // Use consistent index calculation function
    int idx = safe_calc_index<T>(blockIdx.x, blockDim.x, threadIdx.x);

    // Double-check bounds before memory access
    if (idx >= 0 && idx < size) {
        T x = input[idx];
        T x_cubed = x * x * x;
        T inner = SQRT_2_OVER_PI * (x + GELU_COEF * x_cubed);
        T tanh_val = fast_tanh<T>(inner);
        output[idx] = T(0.5f) * x * (T(1.0f) + tanh_val);
    }
    // Note: threads with invalid indices simply do nothing
}

template<>
__global__ void gelu_kernel<half>(const half* __restrict__ input, half* __restrict__ output, int size) {
    // Use the SAME index calculation as other specializations
    int idx = safe_calc_index<half>(blockIdx.x, blockDim.x, threadIdx.x);

    // Same bounds checking pattern
    if (idx >= 0 && idx < size) {
        float x = __half2float(input[idx]);
        float x_cubed = x * x * x;
        float inner = SQRT_2_OVER_PI * (x + GELU_COEF * x_cubed);
        float tanh_val = fast_tanh<float>(inner);
        output[idx] = __float2half(0.5f * x * (1.0f + tanh_val));
    }
}

torch::Tensor gelu_cuda(torch::Tensor input) {
    // Validate input tensor is on CUDA
    TORCH_CHECK(input.is_cuda(), "Input tensor must be on CUDA device");

    at::cuda::CUDAGuard guard(input.device());
    auto size = input.numel();

    // Validate size is reasonable
    TORCH_CHECK(size > 0, "Input tensor must have at least one element");
    TORCH_CHECK(size <= INT_MAX, "Input tensor size exceeds maximum supported size");

    auto output = torch::empty_like(input);

    const int block_size = 256;
    const int num_blocks = (size + block_size - 1) / block_size;

    // Additional check: ensure we don't launch too many blocks
    TORCH_CHECK(num_blocks <= 65535, "Too many blocks required for kernel launch");

    AT_DISPATCH_FLOATING_TYPES_AND_HALF(input.scalar_type(), "gelu_cuda", [&] {
        gelu_kernel<scalar_t><<<num_blocks, block_size>>>(
            input.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            static_cast<int>(size)
        );
    });

    // Check for CUDA errors after kernel launch
    TORCH_CHECK(cudaGetLastError() == cudaSuccess, "CUDA kernel execution failed");

    return output;
}
"""

gelu_cpp_source = "torch::Tensor gelu_cuda(torch::Tensor input);"

# Compile the inline CUDA code for GELU
gelu_module = load_inline(
    name="gelu",
    cpp_sources=gelu_cpp_source,
    cuda_sources=gelu_source,
    functions=["gelu_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[],
    with_cuda=True,
)

class ModelNew(nn.Module):
    def __init__(self):
        super(ModelNew, self).__init__()
        self.gelu_cuda = gelu_module.gelu_cuda

    def forward(self, x):
        return self.gelu_cuda(x)
